import{_ as t,c as e,o as l,V as o}from"./chunks/framework.35c8bad0.js";const x=JSON.parse('{"title":"面试题[HTTP]","description":"","frontmatter":{"title":"面试题[HTTP]","date":"2023-05-26T00:00:00.000Z"},"headers":[],"relativePath":"blog/interview/230526.md","lastUpdated":1778226456000}'),i={name:"blog/interview/230526.md"},d=o('<h1 id="面试题-http" tabindex="-1">面试题[HTTP] <a class="header-anchor" href="#面试题-http" aria-label="Permalink to &quot;面试题[HTTP]&quot;">​</a></h1><h2 id="_1-http-基础" tabindex="-1">1. HTTP 基础 <a class="header-anchor" href="#_1-http-基础" aria-label="Permalink to &quot;1. HTTP 基础&quot;">​</a></h2><h3 id="_1-1-什么是-http" tabindex="-1">1.1 什么是 HTTP <a class="header-anchor" href="#_1-1-什么是-http" aria-label="Permalink to &quot;1.1 什么是 HTTP&quot;">​</a></h3><p>HTTP（HyperText Transfer Protocol，<strong>超文本传输协议</strong>）是互联网上应用最广泛的一种<strong>网络协议</strong>，它<strong>定义了客户端（如浏览器）和服务器之间如何通信</strong>，用于传输网页、图片、视频等超文本数据。</p><ol><li>核心特点 <ul><li><strong>请求-响应模型</strong>：客户端发送一个请求，服务器返回对应的响应。</li><li><strong>无状态</strong>：每个请求独立，服务器不会记住之前的请求（但可通过Cookie、Session等方式模拟状态）。</li><li><strong>基于TCP</strong>：默认使用80端口（HTTPS使用443端口）。</li><li><strong>明文传输</strong>（HTTP本身不加密，安全版本HTTPS则加密）。</li></ul></li><li>发展历史 <ul><li><strong>HTTP/1.0</strong>：简单，每个请求建立新连接</li><li><strong>HTTP/1.1</strong>：引入持久连接、管道化</li><li><strong>HTTP/2</strong>：多路复用、头部压缩、服务器推送</li><li><strong>HTTP/3</strong>：基于QUIC（UDP），减少延迟</li></ul></li><li>HTTP方法</li><li>HTTP状态码</li></ol><h3 id="_1-2-http-各版本的区别" tabindex="-1">1.2 HTTP 各版本的区别 <a class="header-anchor" href="#_1-2-http-各版本的区别" aria-label="Permalink to &quot;1.2 HTTP 各版本的区别&quot;">​</a></h3><p>按时间顺序对比主要版本的核心区别：</p><ol><li>HTTP/0.9（1991年）—— 最简单的原型 <ul><li><strong>只有 GET 方法</strong>，且响应只能是 HTML 文本。</li><li><strong>无状态、无头部</strong>，服务器响应后立即关闭连接。</li><li>没有状态码（只有实际内容），没有版本号标识。</li></ul></li><li>HTTP/1.0（1996年）—— 扩展能力 <ul><li>引入 <strong>请求方法</strong>（POST、HEAD）、<strong>状态码</strong>（200、404等）、<strong>头部字段</strong>（Content-Type、User-Agent等）。</li><li>支持 <strong>缓存控制</strong>（Expires、If-Modified-Since）。</li><li>缺点：<strong>每次请求建立一次 TCP 连接</strong>，连接无法复用，效率低（队头阻塞、握手开销大）。</li></ul></li><li>HTTP/1.1（1997年）—— 标准化的主力版本 <ul><li><strong>持久连接（Connection: keep-alive）</strong>：默认复用同一 TCP 连接处理多个请求/响应，减少握手延迟。</li><li><strong>管道化（pipelining）</strong>：允许客户端在收到前一个响应前连续发送多个请求，但服务器仍须按顺序响应，<strong>队头阻塞</strong>未完全解决。</li><li><strong>分块传输编码（chunked transfer）</strong>：动态生成内容时可分块发送。</li><li>新增更多方法：PUT、PATCH、DELETE、OPTIONS、TRACE、CONNECT。</li><li><strong>Host 头部</strong>：支持同一 IP 上托管多个域名（虚拟主机）。</li><li>更好的缓存机制（Cache-Control、ETag）。</li></ul></li><li>HTTP/2（2015年）—— 性能革命 <ul><li><strong>二进制分帧层</strong>：将 HTTP 消息拆分为更小的帧（HEADERS、DATA等），不再是文本协议。</li><li><strong>多路复用（Multiplexing）</strong>：在一个 TCP 连接上交错发送多个请求/响应的帧，彻底解决 HTTP/1.x 的队头阻塞。</li><li><strong>头部压缩（HPACK）</strong>：减少重复头部开销。</li><li><strong>服务器推送（Server Push）</strong>：服务器可主动向客户端推送资源（如 HTML 中的 CSS/JS）。</li><li><strong>流优先级</strong>：客户端可指定请求的优先级。</li><li>要求加密（虽未强制，但主流浏览器仅支持基于 TLS 的 HTTP/2，即 h2）。</li></ul></li><li>HTTP/3（2022年）—— 突破 TCP 的限制 <ul><li>底层传输由 <strong>TCP 改为 QUIC 协议（基于 UDP）</strong>。</li><li><strong>解决 TCP 的队头阻塞</strong>：即使某个数据包丢失，也不影响其他流的数据交付。</li><li><strong>0-RTT 快速连接</strong>：首次握手后，后续连接可立即发送数据，大幅减少延迟。</li><li><strong>内置加密和传输可靠性</strong>，QUIC 本身提供类似 TLS 1.3 的加密和纠错机制。</li><li>连接迁移：当用户从 WiFi 切换到移动网络时，连接 ID 不变，无需重建连接。</li></ul></li></ol><p>关键区别总结表</p><table><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">HTTP/1.0</th><th style="text-align:left;">HTTP/1.1</th><th style="text-align:left;">HTTP/2</th><th style="text-align:left;">HTTP/3</th></tr></thead><tbody><tr><td style="text-align:left;">连接复用</td><td style="text-align:left;">无（每请求重建）</td><td style="text-align:left;">持久连接（默认）</td><td style="text-align:left;">多路复用（单连接）</td><td style="text-align:left;">多路复用（单连接）</td></tr><tr><td style="text-align:left;">队头阻塞</td><td style="text-align:left;">严重</td><td style="text-align:left;">请求级（管道化无效）</td><td style="text-align:left;">无（帧级别）</td><td style="text-align:left;">无（流级别，基于UDP）</td></tr><tr><td style="text-align:left;">头部压缩</td><td style="text-align:left;">无</td><td style="text-align:left;">无</td><td style="text-align:left;">HPACK</td><td style="text-align:left;">QPACK</td></tr><tr><td style="text-align:left;">服务器推送</td><td style="text-align:left;">无</td><td style="text-align:left;">无</td><td style="text-align:left;">有</td><td style="text-align:left;">有</td></tr><tr><td style="text-align:left;">传输层</td><td style="text-align:left;">TCP</td><td style="text-align:left;">TCP</td><td style="text-align:left;">TCP</td><td style="text-align:left;">QUIC (UDP)</td></tr><tr><td style="text-align:left;">加密要求</td><td style="text-align:left;">无</td><td style="text-align:left;">无（HTTPS可选）</td><td style="text-align:left;">实际强制（TLS）</td><td style="text-align:left;">强制（QUIC自带）</td></tr><tr><td style="text-align:left;">连接握手（新连接）</td><td style="text-align:left;">3次TCP + 多RTT</td><td style="text-align:left;">3次TCP + 多RTT</td><td style="text-align:left;">3次TCP + TLS</td><td style="text-align:left;">0-1 RTT（QUIC）</td></tr><tr><td style="text-align:left;">典型端口</td><td style="text-align:left;">80</td><td style="text-align:left;">80</td><td style="text-align:left;">443（h2）</td><td style="text-align:left;">443</td></tr></tbody></table><p>实际使用建议</p><ul><li><strong>当前仍广泛使用 HTTP/1.1</strong>，兼容性最好，适用于简单 API 或老旧系统。</li><li><strong>HTTP/2</strong> 是现代 Web 的首选（配合 TLS），能极大提升页面加载速度。</li><li><strong>HTTP/3</strong> 适用于对延迟敏感、弱网环境（如移动 APP、视频直播），但需要服务器和客户端同时支持（目前约 30% 流量已使用）。</li></ul><h3 id="_1-3-http-缓存" tabindex="-1">1.3 HTTP 缓存 <a class="header-anchor" href="#_1-3-http-缓存" aria-label="Permalink to &quot;1.3 HTTP 缓存&quot;">​</a></h3><p>HTTP 缓存是一种减少冗余数据传输、降低服务器负载、提升页面加载速度的重要机制。它通过复用之前获取的资源，避免重复向源服务器请求相同内容。核心概念：两种缓存策略。</p><ol><li><strong>强缓存</strong>（强制缓存） <ul><li><strong>无需与服务器通信，直接使用本地缓存</strong>。</li><li>由响应头中的 <strong><code>Cache-Control</code></strong>（HTTP/1.1）或 <strong><code>Expires</code></strong>（HTTP/1.0，已老旧）控制。</li><li><strong>状态码</strong>：强缓存命中时，浏览器直接返回 <code>200 (from disk cache)</code> 或 <code>200 (from memory cache)</code>，无网络请求。</li></ul></li><li><strong>协商缓存</strong>（对比缓存） <ul><li><strong>与服务器通信，询问资源是否变更</strong>。若未变更，服务器返回 <code>304 Not Modified</code>（无响应体），节省带宽；若已变更，返回新资源（200）。</li><li><strong><code>Last-Modified</code> + <code>If-Modified-Since</code></strong>： <ul><li>服务器返回 <code>Last-Modified: &lt;最后修改时间&gt;</code>，浏览器后续请求携带 <code>If-Modified-Since: &lt;该时间&gt;</code>。</li><li>缺点：时间精度只能到秒，毫秒级变动无法感知；文件内容未改但时间变化会误触发更新。</li></ul></li><li><strong><code>ETag</code> + <code>If-None-Match</code></strong>（优先级更高）： <ul><li>服务器返回一个唯一标识（如文件哈希），浏览器下次请求携带 <code>If-None-Match: &lt;该标识&gt;</code>。 可精确判断内容是否变化，推荐使用。</li></ul></li></ul></li><li>常见问题 <ul><li><strong>Ctrl+F5（强制刷新）</strong>：忽略所有缓存，请求头携带 <code>Cache-Control: no-cache</code> 和 <code>Pragma: no-cache</code>，协商缓存也失效。</li><li><strong>普通刷新（F5）</strong>：跳过强缓存，但会携带协商缓存头（<code>If-Modified-Since</code> / <code>If-None-Match</code>）。</li><li><strong>后退/前进</strong>：可能直接使用强缓存。</li></ul></li></ol><h3 id="_1-4-http-方法" tabindex="-1">1.4 HTTP 方法 <a class="header-anchor" href="#_1-4-http-方法" aria-label="Permalink to &quot;1.4 HTTP 方法&quot;">​</a></h3><p>HTTP 方法用于<strong>指示对指定资源执行的操作</strong>。每个请求方法都有其语义，并且一些方法具有 <strong>安全</strong>（不改变服务器状态）和 <strong>幂等</strong>（多次执行效果相同）的特性。</p><table><thead><tr><th style="text-align:left;">方法</th><th style="text-align:left;">安全性</th><th style="text-align:left;">幂等性</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>GET</strong></td><td style="text-align:left;">✅ 安全</td><td style="text-align:left;">✅ 幂等</td><td style="text-align:left;">请求指定的资源。<strong>不应有副作用</strong>，仅用于获取数据。</td></tr><tr><td style="text-align:left;"><strong>HEAD</strong></td><td style="text-align:left;">✅ 安全</td><td style="text-align:left;">✅ 幂等</td><td style="text-align:left;">与 GET 类似，但服务器只返回响应头（无响应体），常用于检查资源是否存在或获取元信息（如 Content-Length）。</td></tr><tr><td style="text-align:left;"><strong>POST</strong></td><td style="text-align:left;">❌ 不安全</td><td style="text-align:left;">❌ 不幂等</td><td style="text-align:left;">向服务器提交数据（如表单、上传文件），导致服务器状态变化。每次请求可能产生不同结果（例如多次提交生成多个订单）。</td></tr><tr><td style="text-align:left;"><strong>PUT</strong></td><td style="text-align:left;">❌ 不安全</td><td style="text-align:left;">✅ 幂等</td><td style="text-align:left;">用请求的载荷替换目标资源的所有内容。若资源不存在，部分实现会创建它。多次相同的 PUT 请求效果一致。</td></tr><tr><td style="text-align:left;"><strong>DELETE</strong></td><td style="text-align:left;">❌ 不安全</td><td style="text-align:left;">✅ 幂等</td><td style="text-align:left;">删除指定的资源。</td></tr><tr><td style="text-align:left;"><strong>PATCH</strong></td><td style="text-align:left;">❌ 不安全</td><td style="text-align:left;">❌ 不幂等（通常）</td><td style="text-align:left;">对资源进行<strong>部分修改</strong>。由于修改内容可能是增量（如 JSON Patch），多次相同请求可能效果不同，因此一般视为非幂等。</td></tr><tr><td style="text-align:left;"><strong>OPTIONS</strong></td><td style="text-align:left;">✅ 安全</td><td style="text-align:left;">✅ 幂等</td><td style="text-align:left;">返回服务器支持的 HTTP 方法（通过 <code>Allow</code> 响应头），用于 CORS 预检请求。</td></tr><tr><td style="text-align:left;"><strong>CONNECT</strong></td><td style="text-align:left;">❌ 不安全</td><td style="text-align:left;">❌ 不幂等</td><td style="text-align:left;">将连接转换为透明的 TCP 隧道，通常用于代理与 HTTPS 服务器建立隧道（由代理使用）。</td></tr><tr><td style="text-align:left;"><strong>TRACE</strong></td><td style="text-align:left;">✅ 安全</td><td style="text-align:left;">✅ 幂等</td><td style="text-align:left;">回显服务器收到的请求内容，主要用于调试（可能引发安全风险，许多生产环境禁用）。</td></tr></tbody></table><p>额外说明</p><ul><li><strong>GET vs POST</strong>：GET 参数通过 URL 传递，长度有限且可见；POST 参数在请求体中，更安全（但非加密）且无大小限制。不要用 GET 执行修改操作（如删除）。</li><li><strong>PUT vs POST</strong>：PUT 是“完整替换”，客户端知道资源最终 URL；POST 是“创建附属资源”或“处理非幂等操作”，由服务器决定最终 URL。</li><li><strong>PATCH</strong>：通常使用 <code>application/merge-patch+json</code> 或 <code>application/json-patch+json</code> 格式，描述变更指令。</li></ul><p>实际开发中，RESTful API 主要使用 GET、POST、PUT、PATCH、DELETE、HEAD、OPTIONS。</p><h3 id="_1-5-http-状态码" tabindex="-1">1.5 HTTP 状态码 <a class="header-anchor" href="#_1-5-http-状态码" aria-label="Permalink to &quot;1.5 HTTP 状态码&quot;">​</a></h3><p>HTTP 状态码（Status Code）是<strong>服务器对客户端请求的响应结果标识</strong>，由三位数字组成，首位数字定义了响应类别。</p><table><thead><tr><th style="text-align:left;">分类</th><th style="text-align:left;">范围</th><th style="text-align:left;">含义</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>1xx</strong></td><td style="text-align:left;">100–101</td><td style="text-align:left;">信息响应</td><td style="text-align:left;">请求已接收，继续处理</td></tr><tr><td style="text-align:left;"><strong>2xx</strong></td><td style="text-align:left;">200–207</td><td style="text-align:left;">成功响应</td><td style="text-align:left;">请求成功完成</td></tr><tr><td style="text-align:left;"><strong>3xx</strong></td><td style="text-align:left;">300–308</td><td style="text-align:left;">重定向</td><td style="text-align:left;">需要进一步操作以完成请求</td></tr><tr><td style="text-align:left;"><strong>4xx</strong></td><td style="text-align:left;">400–451</td><td style="text-align:left;">客户端错误</td><td style="text-align:left;">请求有误或无法处理</td></tr><tr><td style="text-align:left;"><strong>5xx</strong></td><td style="text-align:left;">500–511</td><td style="text-align:left;">服务器错误</td><td style="text-align:left;">服务器处理请求时出错</td></tr></tbody></table><p>常见状态码详解</p><ol><li><p>1xx 信息类</p><ul><li><code>100 Continue</code>：客户端应继续发送请求（用于 Expect: 100-continue）</li><li><code>101 Switching Protocols</code>：服务器同意升级协议（如 WebSocket）</li></ul></li><li><p>2xx 成功类</p><ul><li><code>200 OK</code>：请求成功，返回内容（取决于方法：GET返回资源，POST返回结果）</li><li><code>201 Created</code>：资源创建成功（常见于 POST/PUT），Location 头可指向新资源</li><li><code>202 Accepted</code>：请求已接收但未处理完（异步处理）</li><li><code>204 No Content</code>：成功但无返回体（常用于 DELETE、PUT 更新不返回数据）</li><li><code>206 Partial Content</code>：返回部分内容（用于断点续传、分块下载），配合 Range 头</li></ul></li><li><p>3xx 重定向类</p><ul><li><code>301 Moved Permanently</code>：资源永久移动到新 URL（后续应使用新地址）</li><li><code>302 Found</code>（HTTP/1.0 临时重定向）：资源临时位于另一 URL，后续仍用原地址</li><li><code>303 See Other</code>：重定向到新 URL，且必须用 GET 请求（常用于 POST 后跳转结果页）</li><li><code>304 Not Modified</code>：资源未修改，可使用缓存（协商缓存命中时返回，无响应体）</li><li><code>307 Temporary Redirect</code>（HTTP/1.1）：与 302 类似，但<strong>不允许改变请求方法</strong>（保持 POST→POST）</li><li><code>308 Permanent Redirect</code>（HTTP/1.1）：与 301 类似，但<strong>不允许改变请求方法</strong></li></ul><blockquote><p>注意：302 在实践中有歧义，部分客户端会将 POST 改为 GET，推荐使用 303 或 307。</p></blockquote></li><li><p>4xx 客户端错误类</p><ul><li><code>400 Bad Request</code>：服务器无法理解请求（语法错误、参数错误、请求头过大等）</li><li><code>401 Unauthorized</code>：需要身份验证（未登录或凭证无效），响应头应包含 <code>WWW-Authenticate</code></li><li><code>403 Forbidden</code>：服务器理解请求但拒绝执行（无权限，且不提供登录方式）</li><li><code>404 Not Found</code>：资源不存在（或服务器故意掩盖存在性）</li><li><code>405 Method Not Allowed</code>：请求方法不被允许（如 GET 要求但接口只支持 POST），响应头 <code>Allow: GET, HEAD</code></li><li><code>406 Not Acceptable</code>：请求的 <code>Accept</code> 头要求的内容类型服务器无法提供</li><li><code>408 Request Timeout</code>：客户端未在服务器等待时间内发送完整请求</li><li><code>409 Conflict</code>：请求与当前资源状态冲突（如文件编辑冲突）</li><li><code>410 Gone</code>：资源已永久删除，类似 404 但明确表示“不再可用”</li><li><code>413 Payload Too Large</code>：请求体超过服务器限制</li><li><code>415 Unsupported Media Type</code>：请求的 Content-Type 不被支持</li><li><code>418 I&#39;m a teapot</code>：愚人节彩蛋，源自茶壶超文本咖啡壶控制协议（ RFC 2324）</li><li><code>422 Unprocessable Content</code>（WebDAV）：语义正确但无法处理（例如参数校验失败）</li><li><code>429 Too Many Requests</code>：请求频率超限（常用于限流）</li></ul></li><li><p>5xx 服务器错误类</p><ul><li><code>500 Internal Server Error</code>：服务器内部错误（通用错误，无法定位具体问题）</li><li><code>501 Not Implemented</code>：服务器不支持请求的功能（如某个方法未实现）</li><li><code>502 Bad Gateway</code>：网关/代理服务器收到上游无效响应（如 PHP-FPM 挂掉）</li><li><code>503 Service Unavailable</code>：服务器暂时不可用（超载或维护），可包含 <code>Retry-After</code> 头</li><li><code>504 Gateway Timeout</code>：网关/代理等待上游响应超时</li><li><code>505 HTTP Version Not Supported</code>：服务器不支持请求中使用的 HTTP 版本</li></ul></li></ol><h2 id="_2-http-进阶" tabindex="-1">2. HTTP 进阶 <a class="header-anchor" href="#_2-http-进阶" aria-label="Permalink to &quot;2. HTTP 进阶&quot;">​</a></h2><h3 id="_2-1-restful-api" tabindex="-1">2.1 Restful API <a class="header-anchor" href="#_2-1-restful-api" aria-label="Permalink to &quot;2.1 Restful API&quot;">​</a></h3><p>RESTful API 是一种遵循 REST（Representational State Transfer，表现层状态转移）架构风格的 <strong>API 设计规范</strong>。它不是协议或标准，而是一组设计原则，使 API 更简洁、可扩展、易理解。</p><p>RESTful API 的核心思想是：<strong>利用 HTTP 协议的能力，把一切操作抽象为对资源的管理</strong>。</p><p>RESTful API 核心设计要素：</p><ol><li><p>资源（Resource）</p><ul><li>一切都是资源，用 <strong>URI</strong> 标识（名词，而非动词）。</li><li>示例：<code>/users</code>、<code>/orders/123</code>、<code>/users/456/orders</code></li></ul></li><li><p>HTTP 方法（动作）</p><table><thead><tr><th style="text-align:left;">方法</th><th style="text-align:left;">用途</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;">GET</td><td style="text-align:left;">获取资源</td><td style="text-align:left;"><code>GET /users</code> → 用户列表</td></tr><tr><td style="text-align:left;">POST</td><td style="text-align:left;">创建子资源</td><td style="text-align:left;"><code>POST /users</code> → 新增用户</td></tr><tr><td style="text-align:left;">PUT</td><td style="text-align:left;">完整替换资源（幂等）</td><td style="text-align:left;"><code>PUT /users/123</code> → 整体更新用户</td></tr><tr><td style="text-align:left;">PATCH</td><td style="text-align:left;">部分更新（非幂等）</td><td style="text-align:left;"><code>PATCH /users/123</code> → 修改邮箱</td></tr><tr><td style="text-align:left;">DELETE</td><td style="text-align:left;">删除资源</td><td style="text-align:left;"><code>DELETE /users/123</code> → 删除用户</td></tr></tbody></table></li></ol><p>RESTful API 最佳实践：</p><ol><li>URI 命名规范 <ul><li>使用 <strong>复数名词</strong>：<code>/products</code> 而非 <code>/product</code></li><li>多层路径：<code>/authors/12/books</code></li><li>避免动词：❌ <code>/getUsers</code>，✅ <code>/users</code></li><li>用 <code>/</code> 表示层级，用 <code>-</code> 或 <code>_</code> 提高可读性，全部小写</li><li>过滤/排序/分页使用查询参数：<code>/users?role=admin&amp;page=2&amp;sort=name</code></li></ul></li><li>安全注意事项 <ul><li>敏感操作使用 HTTPS。</li><li>认证常用方式：JWT、OAuth 2.0、API Key。</li><li>对写操作进行 CSRF 防护；限制请求频率（rate limiting）。</li></ul></li></ol><h3 id="_2-2-http-和-https-的区别" tabindex="-1">2.2 HTTP 和 HTTPS 的区别 <a class="header-anchor" href="#_2-2-http-和-https-的区别" aria-label="Permalink to &quot;2.2 HTTP 和 HTTPS 的区别&quot;">​</a></h3><p>HTTP 与 HTTPS 的核心区别在于<strong>安全性</strong>，具体体现在以下几个方面：</p><table><thead><tr><th style="text-align:left;">对比维度</th><th style="text-align:left;">HTTP</th><th style="text-align:left;">HTTPS</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>加密传输</strong></td><td style="text-align:left;">明文传输，数据不加密</td><td style="text-align:left;">使用 SSL/TLS 协议加密，数据密文传输</td></tr><tr><td style="text-align:left;"><strong>端口号</strong></td><td style="text-align:left;">默认 80</td><td style="text-align:left;">默认 443</td></tr><tr><td style="text-align:left;"><strong>身份验证</strong></td><td style="text-align:left;">无服务器身份验证</td><td style="text-align:left;">需向 CA（证书颁发机构）申请数字证书，验证服务器身份</td></tr><tr><td style="text-align:left;"><strong>篡改/监听风险</strong></td><td style="text-align:left;">高（中间人可轻松窃听、篡改）</td><td style="text-align:left;">低（加密防窃听，摘要防篡改）</td></tr><tr><td style="text-align:left;"><strong>性能</strong></td><td style="text-align:left;">快（无加密握手）</td><td style="text-align:left;">略慢（增加 TLS 握手及加解密损耗，但 HTTP/2 等可优化）</td></tr><tr><td style="text-align:left;"><strong>URL 前缀</strong></td><td style="text-align:left;"><code>http://</code></td><td style="text-align:left;"><code>https://</code></td></tr><tr><td style="text-align:left;"><strong>SEO 与浏览器标识</strong></td><td style="text-align:left;">主流浏览器标记为“不安全”</td><td style="text-align:left;">显示安全锁图标，利于搜索排名</td></tr></tbody></table><ol><li>工作原理简述 <ul><li><strong>HTTP</strong>：直接基于 TCP 传输纯文本，请求/响应可被任意中间节点读取。</li><li><strong>HTTPS = HTTP + SSL/TLS</strong>：先进行 TLS 握手（协商加密算法、交换证书、生成会话密钥），随后所有 HTTP 数据均用会话密钥加密传输。</li></ul></li><li>实际建议 <ul><li><strong>任何涉及登录、支付、个人信息等敏感数据的场景</strong>必须使用 HTTPS。</li><li><strong>现代 Web 推荐全站 HTTPS</strong>，即使无敏感信息（可防止劫持、运营商广告注入）。</li><li>启用 HTTPS 需要证书（可用 Let‘s Encrypt 免费获取）。</li></ul></li></ol><h3 id="_2-3-http-和-tcp-长链接的区别" tabindex="-1">2.3 HTTP 和 TCP 长链接的区别 <a class="header-anchor" href="#_2-3-http-和-tcp-长链接的区别" aria-label="Permalink to &quot;2.3 HTTP 和 TCP 长链接的区别&quot;">​</a></h3><p>要理解 <strong>HTTP 长连接</strong> 与 <strong>TCP 长连接</strong> 的区别，首先需要明确：HTTP 长连接本质上还是基于 TCP 的，只是两者关注的层次和细节不同。</p><ol><li><p>基本定义</p><ul><li><strong>HTTP 长连接</strong>（通常称为 HTTP Keep‑Alive 或持久连接）：在同一个 TCP 连接上连续发送多个 HTTP 请求/响应，避免每次请求都重新进行 TCP 三次握手和 TLS 握手。</li><li><strong>TCP 长连接</strong>：指 TCP 连接建立后不立即关闭，而是保持打开状态，供上层应用（不限于 HTTP）多次发送数据。通常需要应用层或操作系统发送“心跳”来维持。</li></ul></li><li><p>核心区别</p><table><thead><tr><th style="text-align:left;">对比维度</th><th style="text-align:left;">HTTP 长连接</th><th style="text-align:left;">TCP 长连接</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>协议层次</strong></td><td style="text-align:left;">应用层（HTTP 协议中的优化机制）</td><td style="text-align:left;">传输层（TCP 协议本身的连接特性）</td></tr><tr><td style="text-align:left;"><strong>控制方式</strong></td><td style="text-align:left;">通过 HTTP 头部 <code>Connection: keep-alive</code>、<code>Keep-Alive: timeout=5, max=100</code> 等协商</td><td style="text-align:left;">由应用程序或操作系统通过 <code>SO_KEEPALIVE</code> 选项（TCP Keep‑Alive）或自定义心跳包来维持</td></tr><tr><td style="text-align:left;"><strong>作用范围</strong></td><td style="text-align:left;">仅在 HTTP 请求/响应之间复用连接</td><td style="text-align:left;">可用于任何基于 TCP 的协议（HTTP、SMTP、自定义协议等）</td></tr><tr><td style="text-align:left;"><strong>典型超时设定</strong></td><td style="text-align:left;">通常较短（几秒到几分钟），由服务器配置（如 Nginx 的 <code>keepalive_timeout</code>）</td><td style="text-align:left;">通常较长（几小时甚至永久），或通过应用层心跳保活</td></tr><tr><td style="text-align:left;"><strong>连接关闭</strong></td><td style="text-align:left;">一方发送 <code>Connection: close</code> 或达到超时/最大请求数后主动关闭</td><td style="text-align:left;">需要应用明确调用 <code>close()</code>，或因为错误/超时而被动关闭</td></tr><tr><td style="text-align:left;"><strong>对请求的处理</strong></td><td style="text-align:left;">一个 HTTP 长连接中，请求必须按照发送顺序依次响应（HTTP/1.1 存在队头阻塞）</td><td style="text-align:left;">TCP 长连接可以承载任意顺序的二进制数据帧（如 HTTP/2 多路复用）</td></tr></tbody></table></li><li><p>常见误解澄清</p><ul><li><strong>HTTP 长连接 ≠ TCP 长连接</strong>：HTTP Keep‑Alive 只是复用 TCP 连接的一种应用层约定；而 TCP 长连接是泛指连接被持续使用，不限于 HTTP。</li><li><strong>TCP Keep‑Alive ≠ HTTP Keep‑Alive</strong>： <ul><li>TCP Keep‑Alive 是操作系统的空闲探测机制（默认通常关闭，开启后每隔一段时间发送空探测包，确认对端是否存活）。</li><li>HTTP Keep‑Alive 是应用层让连接不立即关闭的协商。</li></ul></li><li><strong>HTTP/2 和 HTTP/3 进一步改变了“长连接”的含义</strong><ul><li>HTTP/2 在一个 TCP 连接上实现多路复用，依然是 HTTP 长连接的延伸。</li><li>HTTP/3 基于 QUIC（UDP），不再依赖 TCP 长连接的概念，但内部有自己的连接复用与保活。</li></ul></li></ul></li><li><p>总结</p><ul><li><strong>HTTP 长连接</strong>是应用层对 TCP 连接的<strong>复用策略</strong>，目的是节省 HTTP 请求的建连开销。</li><li><strong>TCP 长连接</strong>是传输层<strong>连接的生命周期特性</strong>，可能被任何上层协议使用。</li></ul><p>两者互不冲突：HTTP 长连接依赖于 TCP 长连接（不关连），但 TCP 长连接不必用于 HTTP。</p></li></ol><h2 id="_3-http-拓展" tabindex="-1">3. HTTP 拓展 <a class="header-anchor" href="#_3-http-拓展" aria-label="Permalink to &quot;3. HTTP 拓展&quot;">​</a></h2><h3 id="_3-1-除了-http-和-https-前端开发中还涉及到哪些通信协议" tabindex="-1">3.1 除了 HTTP 和 HTTPS，前端开发中还涉及到哪些通信协议 <a class="header-anchor" href="#_3-1-除了-http-和-https-前端开发中还涉及到哪些通信协议" aria-label="Permalink to &quot;3.1 除了 HTTP 和 HTTPS，前端开发中还涉及到哪些通信协议&quot;">​</a></h3><ol><li>WebSocket：WebSocket 是一种在单个 TCP 连接上进行全双工通信的协议。相比于传统的 HTTP 请求-响应模式，WebSocket 允许服务器主动向客户端发送数据，实现实时通信。在前端开发中，可以使用 WebSocket 协议来建立持久连接，实现实时聊天、实时数据更新等功能。</li><li>WebRTC：WebRTC（Web 实时通信）是一项基于浏览器的实时通信技术，允许在浏览器之间进行点对点的音视频通信和数据传输，而无需借助插件或其他第三方软件。WebRTC 使用了多种协议和 API，包括实时传输协议（RTP）、会话描述协议（SDP）等。前端开发者可以利用 WebRTC 实现音视频通话、屏幕共享等实时通信应用。</li><li>MQTT：MQTT（Message Queuing Telemetry Transport）是一种轻量级的发布/订阅消息传输协议。它被设计用于低带宽、不稳定网络环境下的物联网设备通信。前端开发中，可以利用 MQTT 协议实现与物联网设备的通信，获取传感器数据、控制设备等。</li><li>RESTful API：虽然 REST（Representational State Transfer）本身不是一种通信协议，但它是一种架构风格，常用于设计 Web API。RESTful API 使用标准的 HTTP 方法（如 GET、POST、PUT、DELETE）进行通信，通过请求资源的 URL 来表达操作，并使用 HTTP 状态码表示响应状态。前端开发者可以通过使用 RESTful API 与服务器进行数据交互。</li><li>FTP（File Transfer Protocol）：FTP 是一种用于在客户端和服务器之间传输文件的协议。在前端开发中，可以使用 FTP 协议来上传、下载和管理网站文件。</li><li>SSH（Secure Shell）：SSH 是一种加密的网络协议，用于远程登录到服务器并执行命令。前端开发人员可以使用 SSH 协议来通过终端或命令行界面连接到远程服务器，进行文件操作、运行程序等任务。</li><li>DNS（Domain Name System）：DNS 是一种用于将域名转换为 IP 地址的协议。在前端开发中，当用户输入一个域名时，浏览器会使用 DNS 协议将域名解析为相应的 IP 地址，以便建立与服务器的通信。</li></ol><h3 id="_3-2-cors-跨域是如何做的-从协议的角度去讲一下" tabindex="-1">3.2 CORS 跨域是如何做的？从协议的角度去讲一下 <a class="header-anchor" href="#_3-2-cors-跨域是如何做的-从协议的角度去讲一下" aria-label="Permalink to &quot;3.2 CORS 跨域是如何做的？从协议的角度去讲一下&quot;">​</a></h3><p>CORS（跨域资源共享）是一种用于解决浏览器的同源策略限制，允许在不同域名之间进行跨域请求的机制。<strong>从协议的角度来看，CORS通过HTTP头部字段进行通信</strong>。</p><p>以下是CORS的基本工作原理：</p><ol><li>简单请求：对于简单请求（例如GET、POST、HEAD等），浏览器会在实际发送请求前，自动发送一个预检请求（Preflight request）来获取服务器的许可。预检请求是一个OPTIONS方法的HTTP请求，其中包含一些额外的头部字段。</li><li>预检请求：预检请求包含了一些关键信息，如请求方法、请求头、请求的目标URL等。服务器收到预检请求后，需要进行验证并返回响应，确认是否允许跨域请求。验证的方式包括检查Origin头部字段、Access-Control-Request-Method头部字段、Access-Control-Request-Headers头部字段等。</li><li>响应处理：如果服务器确认允许跨域请求，它会在响应中返回一些特定的头部字段，以授权浏览器访问响应的内容。这些头部字段包括Access-Control-Allow-Origin、Access-Control-Allow-Methods、Access-Control-Allow-Headers等。</li><li>安全限制：浏览器会根据响应头部字段进行安全限制，只有在响应中包含了正确的头部字段，浏览器才会允许跨域请求，并将响应的内容返回给前端。</li></ol><p>需要注意的是，<strong>CORS机制只对浏览器发起的异步请求（如Ajax请求）有效</strong>，而对于直接在浏览器地址栏中输入URL的同步请求，则不会触发CORS限制。通过CORS机制，服务器可以灵活地控制哪些域名可以访问其资源，从而提高Web应用程序的安全性和可扩展性。</p><p>从协议的角度来看，CORS是通过HTTP头部字段进行通信的。具体来说，CORS使用了以下几个HTTP头部字段：</p><ol><li>Origin：表示浏览器发起请求的源地址（协议+域名+端口号），例如<a href="http://www.example.com/" target="_blank" rel="noreferrer">http://www.example.com</a>。</li><li>Access-Control-Request-Method：表示浏览器实际发送的请求方法，例如GET、POST、PUT等。</li><li>Access-Control-Request-Headers：表示浏览器实际发送的请求头部信息，例如Content-Type、Authorization等。</li><li>Access-Control-Allow-Origin：表示服务器允许请求的源地址，可以是单个域名、多个域名、或者通配符*。</li><li>Access-Control-Allow-Methods：表示服务器允许请求的方法，例如GET、POST、PUT等。</li><li>Access-Control-Allow-Headers：表示服务器允许请求的头部信息，例如Content-Type、Authorization等。</li></ol><p>当浏览器发起跨域请求时，它会自动在请求头部中添加Origin字段，告诉服务器请求的源地址。服务器在收到请求后，检查Origin字段，如果认为请求合法，则在响应头部中添加Access-Control-Allow-Origin、Access-Control-Allow-Methods和Access-Control-Allow-Headers字段，授权浏览器访问响应的内容。</p><h2 id="_4-websocket" tabindex="-1">4. WebSocket <a class="header-anchor" href="#_4-websocket" aria-label="Permalink to &quot;4. WebSocket&quot;">​</a></h2>',53),n=[d];function s(r,a,T,g,c,P){return l(),e("div",null,n)}const h=t(i,[["render",s]]);export{x as __pageData,h as default};
